const projectsApi = {
  // Get all projects
  getAll: async (filters = {}) => {
    const params = new URLSearchParams();
    if (filters.status) params.append("status", filters.status);
    if (filters.priority) params.append("priority", filters.priority);
    if (filters.search) params.append("search", filters.search);
    const queryString = params.toString();
    const url2 = queryString ? `/projects?${queryString}` : "/projects";
    const response = await api.get(url2);
    return response.data;
  },
  // Get dashboard statistics
  getDashboardStats: async () => {
    const response = await api.get("/projects/dashboard-stats");
    return response.data;
  },
  // Get single project by ID
  getById: async (projectId) => {
    const response = await api.get(`/projects/${projectId}`);
    return response.data;
  },
  // Create new project
  create: async (projectData) => {
    const response = await api.post("/projects", projectData);
    return response.data;
  },
  // Update project
  update: async (projectId, projectData) => {
    const response = await api.put(`/projects/${projectId}`, projectData);
    return response.data;
  },
  // Delete project
  delete: async (projectId) => {
    const response = await api.delete(`/projects/${projectId}`);
    return response.data;
  },
  // Add team member to project
  addTeamMember: async (projectId, userId, role = "member") => {
    const response = await api.post(`/projects/${projectId}/members`, {
      userId,
      role
    });
    return response.data;
  },
  // Remove team member from project
  removeTeamMember: async (projectId, userId) => {
    const response = await api.delete(`/projects/${projectId}/members/${userId}`);
    return response.data;
  }
};
